  1→import { Plus, ChevronRight, ChevronDown, GitPullRequest } from "lucide-react";
  2→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
  3→import { SidebarMenuItem } from "@/components/ui/sidebar";
  4→import { Collapsible, CollapsibleTrigger } from "@/components/ui/collapsible";
  5→import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
  6→import { cn } from "@/shared/lib/utils";
  7→import { getCleanRepoName, splitByRecency } from "../lib/utils";
  8→import { sortByStatusPriority } from "../lib/status";
  9→import { useSidebarStore } from "../store/sidebarStore";
 10→import type { RepositoryItemProps } from "../model/types";
 11→import type { Workspace, DiffStats, RepoGroup } from "@/shared/types";
 12→import type { WorkspaceStatus } from "@shared/enums";
 13→import { WorkspaceItem } from "./WorkspaceItem";
 14→import { RepoAvatar } from "./RepoAvatar";
 15→import { SidebarRow, SidebarRowMain, SidebarRowIconSlot, SidebarRowRight } from "./SidebarRow";
 16→import { OpenDevsRepositoryBanner } from "./OpenDevsRepositoryBanner";
 17→
 18→/** Check if a git remote URL points to GitHub */
 19→function isGitHubUrl(url: string | null | undefined): boolean {
 20→  return !!url && url.includes("github.com");
 21→}
 22→
 23→/**
 24→ * RepositoryItem — V2: Jony Ive
 25→ *
 26→ * Layout:
 27→ *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 28→ *     └── [+ New workspace]
 29→ *     └── WorkspaceItem[]
 30→ *
 31→ * The repo header uses text-secondary (B0B0B0) 14px medium.
 32→ * Action icons: text-muted (#787878), appear on hover.
 33→ */
 34→export function RepositoryItem({
 35→  repository,
 36→  isCollapsed,
 37→  selectedWorkspaceId,
 38→  onToggleCollapse,
 39→  onWorkspaceClick,
 40→  onNewWorkspace,
 41→  onNewWorkspaceFromGitHub,
 42→  onArchive,
 43→  onStatusChange,
 44→  diffStatsMap,
 45→  sidebarExpanded,
 46→}: RepositoryItemProps) {
 47→  const reduceMotion = useReducedMotion();
 48→  const repoName = getCleanRepoName(repository.repo_name);
 49→  // Detect the opendevs repo by clean name (works for "opendevs" or "org/opendevs")
 50→  const isOpenDevs = repoName === "opendevs";
 51→  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;
 52→
 53→  return (
 54→    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
 55→      <SidebarMenuItem
 56→        data-state={isCollapsed ? "closed" : "open"}
 57→        className="group/repository-item relative"
 58→      >
 59→        <CollapsibleTrigger asChild>
 60→          <SidebarRow
 61→            variant="repo"
 62→            role="button"
 63→            aria-label={`Toggle ${repoName} workspaces`}
 64→            className="cursor-grab"
 65→          >
 66→            <SidebarRowMain className="gap-2">
 67→              <div className="relative flex-shrink-0">
 68→                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
 69→                  <RepoAvatar repoName={repository.repo_name} />
 70→                </div>
 71→                <ChevronRight
 72→                  className={cn(
 73→                    "absolute inset-0 m-auto h-4 w-4",
 74→                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
 75→                    !isCollapsed && "rotate-90"
 76→                  )}
 77→                />
 78→              </div>
 79→              <span className="text-text-secondary truncate text-sm font-medium">{repoName}</span>
 80→              {workspaceCount > 0 && (
 81→                <span className="text-text-muted text-xs tabular-nums">{workspaceCount}</span>
 82→              )}
 83→            </SidebarRowMain>
 84→            {sidebarExpanded && (
 85→              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
 86→                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
 87→                  <Tooltip>
 88→                    <TooltipTrigger asChild>
 89→                      <button
 90→                        type="button"
 91→                        aria-label={`New workspace from PR or branch in ${repoName}`}
 92→                        onClick={(e) => {
 93→                          e.stopPropagation();
 94→                          onNewWorkspaceFromGitHub(repository.repo_id);
 95→                        }}
 96→                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
 97→                      >
 98→                        <GitPullRequest className="h-4 w-4" />
 99→                      </button>
100→                    </TooltipTrigger>
101→                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
102→                  </Tooltip>
103→                )}
104→                <Tooltip>
105→                  <TooltipTrigger asChild>
106→                    <button
107→                      type="button"
108→                      aria-label={`New workspace in ${repoName}`}
109→                      onClick={(e) => {
110→                        e.stopPropagation();
111→                        onNewWorkspace(repository.repo_id);
112→                      }}
113→                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
114→                    >
115→                      <Plus className="h-4 w-4" />
116→                    </button>
117→                  </TooltipTrigger>
118→                  <TooltipContent side="bottom">New workspace</TooltipContent>
119→                </Tooltip>
120→              </SidebarRowRight>
121→            )}
122→          </SidebarRow>
123→        </CollapsibleTrigger>
124→      </SidebarMenuItem>
125→      <AnimatePresence initial={false}>
126→        {!isCollapsed && (
127→          <m.ul
128→            key="workspace-list"
129→            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
130→            animate={{ height: "auto", opacity: 1 }}
131→            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
132→            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
133→            className="flex min-w-0 flex-col overflow-hidden"
134→          >
135→            {sidebarExpanded && (
136→              <RepositoryWorkspaceList
137→                repository={repository}
138→                isOpenDevs={isOpenDevs}
139→                selectedWorkspaceId={selectedWorkspaceId}
140→                diffStatsMap={diffStatsMap}
141→                reduceMotion={reduceMotion}
142→                onNewWorkspace={onNewWorkspace}
143→                onWorkspaceClick={onWorkspaceClick}
144→                onArchive={onArchive}
145→                onStatusChange={onStatusChange}
146→              />
147→            )}
148→          </m.ul>
149→        )}
150→      </AnimatePresence>
151→    </Collapsible>
152→  );
153→}
