155→// ── Inner list with stale-workspace collapsing ───────────────────────────
156→
157→interface RepositoryWorkspaceListProps {
158→  repository: RepoGroup;
159→  isOpenDevs: boolean;
160→  selectedWorkspaceId: string | null;
161→  diffStatsMap?: Record<string, DiffStats>;
162→  reduceMotion: boolean | null;
163→  onNewWorkspace: (repoId?: string) => void;
164→  onWorkspaceClick: (workspace: Workspace) => void;
165→  onArchive?: (workspaceId: string) => void;
166→  onStatusChange?: (workspaceId: string, status: WorkspaceStatus) => void;
167→}
168→
